UPDATE tbl_offer_response
   SET viewed_at = SYSDATE
 WHERE fk_offer_submit_id = #{offerSubmitId}
   AND fk_memberid = #{memberId}
   AND viewed_at IS NULL

UPDATE tbl_offer_response
   SET response_status = 1,
       responded_at = SYSDATE
 WHERE fk_offer_submit_id = #{offerSubmitId}
   AND fk_memberid = #{memberId}
   AND response_status = 0
   AND fk_offer_submit_id IN (
       SELECT offer_submit_id FROM tbl_offer_submit
       WHERE offer_submit_id = #{offerSubmitId}
         AND (expire_at IS NULL OR expire_at >= TRUNC(SYSDATE))
   )

UPDATE tbl_offer_response
   SET response_status = 2,
       responded_at = SYSDATE
 WHERE fk_offer_submit_id = #{offerSubmitId}
   AND fk_memberid = #{memberId}
   AND response_status = 0
   AND fk_offer_submit_id IN (
       SELECT offer_submit_id FROM tbl_offer_submit
       WHERE offer_submit_id = #{offerSubmitId}
         AND (expire_at IS NULL OR expire_at >= TRUNC(SYSDATE))
   )
